### Applying Profile Constraints

To apply these constraints, you can use a FHIR server that supports profiles (e.g., SMART on FHIR servers). You would define and publish this profile to ensure that all observations adhere to the specified constraints.

#### Example Usage in Python with `fhirclient`:

```python
from fhirclient.models.observation import Observation

def fetch_vital_signs(patient_id):
    # Fetch vital signs from FHIR server
    client = Client(settings={
        'app_id': "your_client_id",
        'api_base': "https://ehr-system.com/fhir"
    })

    systolic_bp = Observation.where({"patient": patient_id, "code": "http://loinc.org|55284-4"}).perform(client)
    diastolic_bp = Observation.where({"patient": patient_id, "code": "http://loinc.org|3196-0"}).perform(client)

    return {
        'systolic': [obs.as_json() for obs in systolic_bp.entry],
        'diastolic': [obs.as_json() for obs in diastolic_bp.entry]
    }

def validate_observation(obs):
    # Ensure the observation meets the profile constraints
    if not obs.code.coding or len(obs.code.coding) == 0:
        return False

    if not obs.effectiveDateTime:
        return False

    if not obs.valueQuantity:
        return False

    return True

# Example usage
patient_id = "12345"
try:
    vital_signs_data = fetch_vital_signs(patient_id)

    for systolic_obs in vital_signs_data['systolic']:
        if not validate_observation(Observation(systolic_obs)):
            raise ValueError("Systolic BP observation does not meet required profile constraints")

    for diastolic_obs in vital_signs_data['diastolic']:
        if not validate_observation(Observation(diastolic_obs)):
            raise ValueError("Diastolic BP observation does not meet required profile constraints")

    print(f"Vital signs data: {vital_signs_data}")
except ValueError as e:
    print(e)
```

